const fs = require("fs");
const path = require("path");

const root = path.resolve(__dirname, "..");
const modelDir = path.join(root, "assets", "models", "gemma");
const generatedDir = path.join(root, "src", "generated");
const manifestPath = path.join(generatedDir, "gemma-bundle.ts");

const required = [
  { key: "modelSource", label: "model", filename: "model.pte" },
  { key: "tokenizerSource", label: "tokenizer", filename: "tokenizer.gemmajson" },
  { key: "tokenizerConfigSource", label: "tokenizer config", filename: "tokenizer_config.gemmajson" },
];

const strict =
  process.argv.includes("--strict") ||
  process.env.USELANG_REQUIRE_BUNDLED_GEMMA === "1" ||
  process.env.EAS_BUILD_PROFILE === "production" ||
  process.env.NODE_ENV === "production";

function exists(file) {
  try {
    return fs.statSync(file).isFile() && fs.statSync(file).size > 0;
  } catch {
    return false;
  }
}

const missing = required.filter((item) => !exists(path.join(modelDir, item.filename)));

fs.mkdirSync(generatedDir, { recursive: true });

const allPresent = missing.length === 0;
const sourceLines = required.map((item) => {
  if (!allPresent) return `  ${item.key}: null,`;
  return `  ${item.key}: require("../../assets/models/gemma/${item.filename}"),`;
});

// Note: `bundled` is typed as `boolean` (not the literal value) so the
// generated manifest compiles cleanly under either branch of the engine's
// `bundled === true` check. Without this widening, dev builds fail tsc with
// "comparison appears to be unintentional".
const manifest = `// AUTO-GENERATED by scripts/verify-bundled-gemma.js — do not edit.
// Regenerated on every \`npm install\`, \`npm start\`, \`npm run ios\`, and
// \`npm run android\`. Drop the real ExecuTorch Gemma weights into
// assets/models/gemma/ to flip \`bundled\` to true on the next regen.
export interface GemmaBundleManifest {
  readonly bundled: boolean;
  readonly modelSource: number | null;
  readonly tokenizerSource: number | null;
  readonly tokenizerConfigSource: number | null;
}

export const GEMMA_BUNDLE: GemmaBundleManifest = {
  bundled: ${allPresent},
${sourceLines.join("\n")}
};
`;

fs.writeFileSync(manifestPath, manifest);

if (missing.length) {
  const list = missing.map((item) => `- assets/models/gemma/${item.filename}`).join("\n");
  const message = `Bundled Gemma assets are missing:\n${list}\n\nPlace the real ExecuTorch Gemma files in assets/models/gemma/.`;
  if (strict) {
    console.error(message);
    process.exit(1);
  }
  console.warn(`${message}\n\nDevelopment will use the local Gemma stub. No runtime download or cloud LLM will be used.`);
}
